var inputSchema5 = {
  bid_key: external_exports.string().min(1).describe("search_bids\u3001rank_bids\u3001\u307E\u305F\u306Flist_recent_bids\u304C\u8FD4\u3057\u305FKey\u30D5\u30A3\u30FC\u30EB\u30C9"),
  fetch_documents: external_exports.boolean().default(false).describe("true\u306E\u5834\u5408\u3001PDF/HTML\u62BD\u51FA\u7D50\u679C\u3092\u4F7F\u3063\u3066\u8CEA\u554F\u6848\u3092\u7D5E\u308A\u8FBC\u3080\u3002"),
  target_uris: external_exports.array(external_exports.string().url()).max(3).optional().describe("\u62BD\u51FA\u5BFE\u8C61URL\u3002\u7701\u7565\u6642\u306F\u691C\u7D22\u7D50\u679C\u306E\u516C\u5F0F\u516C\u544A\u30DA\u30FC\u30B8\u30FB\u6DFB\u4ED8\u8CC7\u6599URL\u304B\u3089\u6700\u59273\u4EF6\u3092\u4F7F\u3046\u3002")
};
function registerDraftBidQuestions(server, client) {
  server.registerTool(
    "draft_bid_questions",
    {
      title: "\u5165\u672D\u8CEA\u554F\u66F8\u30C9\u30E9\u30D5\u30C8",
      description: "\u5165\u672D1\u4EF6\u306E\u767A\u6CE8\u8005\u3078\u306E\u8CEA\u554F\u6848\u3092Markdown\u3067\u8FD4\u3059\u3002\u63D0\u51FA\u524D\u306B\u516C\u5F0F\u66F8\u985E\u3068\u7167\u5408\u3059\u308B\u3053\u3068\u3002Draft clarification questions for a bid in Markdown format. Buat draf pertanyaan klarifikasi untuk satu tender dalam format Markdown.",
      inputSchema: inputSchema5,
      outputSchema: BidQuestionDraftSchema.shape,
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: true
      }
    },
    async (args) => {
      try {
        const cached2 = client.getCachedBid(args.bid_key);
        const result = cached2 ? { bid: cached2, attribution: createAttribution() } : await findBidByKey4(client, args.bid_key);
        const baseRequirements = extractBidRequirements(result.bid, result.attribution);
        const requirements = args.fetch_documents ? await enrichWithDocumentExtraction(server, baseRequirements, args.target_uris) : baseRequirements;
        const draft = draftBidQuestions(result.bid, result.attribution, requirements);
        return {
          content: [{ type: "text", text: draft.markdown }],
          structuredContent: draft
        };
      } catch (error51) {
        return toolError(
          error51,
          "\u5165\u672D\u8CEA\u554F\u66F8\u30C9\u30E9\u30D5\u30C8\u306E\u4F5C\u6210\u3067\u4E00\u6642\u7684\u306A\u30A8\u30E9\u30FC\u304C\u767A\u751F\u3057\u307E\u3057\u305F\u3002rank_bids \u307E\u305F\u306F search_bids \u3067\u53D6\u5F97\u3057\u305F\u6700\u65B0\u306Ebid_key\u3092\u6307\u5B9A\u3057\u3066\u304F\u3060\u3055\u3044\u3002"
        );
      }
    }
  );
}
async function findBidByKey4(client, bidKey) {
  const searchResult = await client.search({ Query: bidKey, Count: 10 });
  const bid = searchResult.bids.find((candidate) => candidate.key === bidKey);
  if (!bid) {
    throw new UserInputError(
      "\u6307\u5B9A\u3055\u308C\u305F bid_key \u306E\u5165\u672D\u3092\u78BA\u8A8D\u3067\u304D\u307E\u305B\u3093\u3067\u3057\u305F\u3002rank_bids \u307E\u305F\u306F search_bids \u3067\u53D6\u5F97\u3057\u305F\u6700\u65B0\u306E Key \u3092\u6307\u5B9A\u3057\u3066\u304F\u3060\u3055\u3044\u3002"
    );
  }
  return { bid, attribution: searchResult.attribution };
}

