  avoid_keywords: external_exports.array(external_exports.string().min(1)).optional().describe("\u907F\u3051\u305F\u3044\u8A9E\u53E5\u3002\u4F8B: \u5DE5\u4E8B\u3001\u5E38\u99D0\u3001\u591C\u9593\u3002"),
