function createJpBidsServer(options = {}) {
  const tier = options.tier ?? "pro";
  const branding = getBranding();
  const server = new McpServer(
    {
      name: branding.serviceName,
      title: branding.serviceName,
      version: "0.7.1",
      description: "Japan government procurement bid search through the Model Context Protocol."
    },
    {
      capabilities: {
        tools: { listChanged: false },
        resources: { listChanged: false, subscribe: false },
        prompts: { listChanged: false },
        completions: {},
        logging: {}
      },
      instructions: tier === "pro" ? "Use JP Bids MCP to search public Japanese government procurement bid information. Always show the KKJ attribution included in tool results." : "Use JP Bids MCP (Free tier) to search public Japanese government procurement bid information. Available tools: search_bids, rank_bids, list_recent_bids, get_bid_detail. Upgrade to Pro (990 JPY/month) for AI analysis and PDF extraction tools. Always show the KKJ attribution included in tool results."
    }
  );
  const client = options.kkjClient ?? new KkjClient(options.kkjClientOptions);
  registerTools(server, client, tier);
  if (tier === "pro") {
    registerSearchResultsApp(server, client);
  }
  registerPrompts(server);
  registerResources(server, client);
  return server;
}
